use clap::{Parser, Subcommand};

#[derive(Parser)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Add a new item
    Add { name: String },
    /// List all items
    List {
        #[arg(short, long)]
        verbose: bool,
    },
}

#[derive(Parser)]
struct Args {
    /// Input file path
    input: String,

    /// Output file path (optional)
    output: Option<String>,

    /// Enable verbose output
    #[arg(short, long)]
    verbose: bool,

    /// Set log level
    #[arg(long, default_value = "info")]
    log_level: String,
}

use clap::ValueEnum;

#[derive(Clone, ValueEnum)]
enum Format {
    Json,
    Yaml,
    Toml,
}

#[derive(Parser)]
struct Args {
    #[arg(short, long, value_enum, default_value_t = Format::Json)]
    format: Format,
}
